- (NSString *)getDisplayName {
    if (_userInfo && _userInfo.customName && (WBSettingManager.sharedManager.IsVIP || WBSettingManager.sharedManager.IsSVIP)) {
        return _userInfo.customName;
    } else {
        return _name;
    }
